{
var seed = GetInt(parameters, "seed", context.Seed);
    var floorType = GetChoice(parameters, "floorType", "planks");
    var primaryColor = GetColor(parameters, "primaryColor", Color.FromRgb(160, 120, 80));
    var secondaryColor = GetColor(parameters, "secondaryColor", Color.FromRgb(200, 180, 150));
    var width = GetFloat(parameters, "width", 0.9f);
    var height = GetFloat(parameters, "height", 0.8f);

    var size = context.TileSize;
    var buffer = new PixelBuffer(size, size);
    var bg = inputs.Length > 0 ? inputs[0] : null;

    var pR = primaryColor.R / 255f;
    var pG = primaryColor.G / 255f;
    var pB = primaryColor.B / 255f;
    var sR = secondaryColor.R / 255f;
    var sG = secondaryColor.G / 255f;
    var sB = secondaryColor.B / 255f;

    var period = Math.Max(1, size / 3);

    buffer.ParallelForEachPixel((x, y) =>
    {
        var u = (x + 0.5f) / size;
        var v = (y + 0.5f) / size;

        // Floor rectangle
        var left = (1f - width) * 0.5f;
        var right = left + width;
        var top = (1f - height) * 0.5f;
        var bottom = top + height;
        var edgeW = 0.004f;

        var mask = SmoothStep(left - edgeW, left + edgeW, u)
                 * (1f - SmoothStep(right - edgeW, right + edgeW, u))
                 * SmoothStep(top - edgeW, top + edgeW, v)
                 * (1f - SmoothStep(bottom - edgeW, bottom + edgeW, v));

        if (mask < 0.01f)
        {
            if (bg != null) { var (br, bgc, bb, ba) = bg.GetPixel(x, y); buffer.SetPixel(x, y, br, bgc, bb, 0f); }
            else { buffer.SetPixel(x, y, 0f, 0f, 0f, 0f); }
            return;
        }

        var floorU = (u - left) / width;
        var floorV = (v - top) / height;

        float r, g, b;
        switch (floorType)
        {
            case "planks": (r, g, b) = RenderPlanks(floorU, floorV, pR, pG, pB, sR, sG, sB, size, period, seed); break;
            case "herringbone": (r, g, b) = RenderHerringbone(floorU, floorV, pR, pG, pB, sR, sG, sB, size, period, seed); break;
            case "stoneTile": (r, g, b) = RenderStoneTile(floorU, floorV, pR, pG, pB, sR, sG, sB, size, period, seed); break;
            case "carpet": (r, g, b) = RenderCarpet(floorU, floorV, pR, pG, pB, sR, sG, sB, size, period, seed); break;
            default: r = pR; g = pG; b = pB; break;
        }

        r = Math.Clamp(r, 0f, 1f);
        g = Math.Clamp(g, 0f, 1f);
        b = Math.Clamp(b, 0f, 1f);

        if (bg != null)
        {
            var (br, bgc, bb, ba) = bg.GetPixel(x, y);
            r = r * mask + br * (1f - mask);
            g = g * mask + bgc * (1f - mask);
            b = b * mask + bb * (1f - mask);
        }

        buffer.SetPixel(x, y, r, g, b, mask);
    });

    return buffer;

private static (float r, float g, float b) RenderPlanks(float u, float v, float pR, float pG, float pB, float sR, float sG, float sB, int size, int period, int seed)
{
    // Horizontal floor planks with gaps
    var plankCount = 5f;
    var plankH = 1f / plankCount;
    var row = (int)(v * plankCount);
    var cellV = (v - row * plankH) / plankH;
    var gap = 0.04f;

    if (cellV < gap || cellV > 1f - gap)
    {
        return (0.08f, 0.06f, 0.04f);
    }

    var plankHash = HashToUnit(row, 0, seed + 50);
    var shade = 0.75f + 0.25f * plankHash;
    var r = pR * shade;
    var g = pG * shade * 0.95f;
    var b = pB * shade * 0.9f;

    // Horizontal wood grain
    var grain = MathF.Sin(u * 20f + v * 5f + plankHash * 8f) * 0.03f;
    var grainNoise = TileableFractalNoise(u * 4f, v * 3f + row * 2f, period, 2, 0.5f, 2.5f, seed + 80);
    grain += (grainNoise - 0.5f) * 0.03f;
    r += grain; g += grain * 0.7f; b += grain * 0.4f;

    return (Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f));
}

private static (float r, float g, float b) RenderHerringbone(float u, float v, float pR, float pG, float pB, float sR, float sG, float sB, int size, int period, int seed)
{
    // Herringbone pattern at 45 degrees
    var scale = 4f;
    var su = u * scale;
    var sv = v * scale;

    // Rotate 45 degrees
    var ru = (su + sv) * 0.5f;
    var rv = (sv - su) * 0.5f;

    var plankW = 0.25f;
    var cellU = (ru % plankW + plankW) % plankW / plankW;
    var cellV = (rv % 1f + 1f) % 1f;

    var gap = 0.06f;
    var isGap = cellU < gap || cellU > 1f - gap;

    if (isGap)
    {
        return (0.06f, 0.04f, 0.03f);
    }

    var plankIdx = (int)MathF.Floor(ru / plankW) + (int)MathF.Floor(rv);
    var hash = HashToUnit(plankIdx, 0, seed + 120);
    var shade = 0.8f + 0.2f * hash;

    var r = pR * shade;
    var g = pG * shade * 0.95f;
    var b = pB * shade * 0.9f;

    var grain = MathF.Sin(rv * 30f + ru * 10f) * 0.03f;
    r += grain; g += grain * 0.7f; b += grain * 0.4f;

    return (Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f));
}

private static (float r, float g, float b) RenderStoneTile(float u, float v, float pR, float pG, float pB, float sR, float sG, float sB, int size, int period, int seed)
{
    // Square stone tiles in grid
    var cols = 4f;
    var rows = 4f;
    var cellW = 1f / cols;
    var cellH = 1f / rows;
    var col = (int)(u * cols);
    var row = (int)(v * rows);
    var cellU = (u - col * cellW) / cellW;
    var cellV = (v - row * cellH) / cellH;
    var gap = 0.04f;

    if (cellU < gap || cellU > 1f - gap || cellV < gap || cellV > 1f - gap)
    {
        return (0.15f, 0.13f, 0.11f);
    }

    var tileHash = HashToUnit(col, row, seed + 200);
    var useSecondary = tileHash > 0.7f;
    var baseR = useSecondary ? sR : pR;
    var baseG = useSecondary ? sG : pG;
    var baseB = useSecondary ? sB : pB;

    var shade = 0.8f + 0.2f * tileHash;
    var r = baseR * shade;
    var g = baseG * shade * 0.95f;
    var b = baseB * shade * 0.9f;

    // Subtle surface noise
    var noise = TileableFractalNoise(u * 4f, v * 4f, period, 1, 0.5f, 2f, seed + 300);
    var n = (noise - 0.5f) * 0.04f;
    r += n; g += n * 0.9f; b += n * 0.85f;

    return (Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f));
}

private static (float r, float g, float b) RenderCarpet(float u, float v, float pR, float pG, float pB, float sR, float sG, float sB, int size, int period, int seed)
{
    // Woven carpet with checkered/striped pattern
    var r = pR;
    var g = pG;
    var b = pB;

    // Subtle woven texture
    var weaveX = MathF.Sin(u * 30f * MathF.PI * 2f) * 0.015f;
    var weaveY = MathF.Sin(v * 30f * MathF.PI * 2f) * 0.015f;
    r += weaveX + weaveY;
    g += (weaveX + weaveY) * 0.95f;
    b += (weaveX + weaveY) * 0.9f;

    // Subtle checkered pattern using secondary color
    var checkScale = 6f;
    var checkX = MathF.Floor(u * checkScale);
    var checkY = MathF.Floor(v * checkScale);
    var check = ((int)(checkX + checkY) % 2 == 0) ? 0f : 0.08f;
    r = Lerp(r, sR, check);
    g = Lerp(g, sG, check);
    b = Lerp(b, sB, check);

    // Fibrous noise
    var fiberNoise = TileableFractalNoise(u * 12f, v * 12f, period, 2, 0.5f, 2f, seed + 400);
    var fiber = (fiberNoise - 0.5f) * 0.04f;
    r += fiber; g += fiber * 0.95f; b += fiber * 0.9f;

    return (Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f));
    }
}
